pub struct CallInfoIdx(pub u32);

impl CallInfoIdx {
    pub const ZERO: Self = CallInfoIdx(0);
    pub fn get(self) -> u32 { self.0 }
    pub fn as_usize(self) -> usize { self.0 as usize }
}

